  ('colonel-7fec267e-moex-00103', 'colonel-7fec267e', 'colonel-7fec267e-moex-113-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '土地所有權人甲於1月3日收到新北市政府工務局所開立「申請建築執照 補件通知單」，通知其應於30日內依建築法規定補件，但甲不服並於3月 3日提起訴願。下列何者正確？', '["該補件通知單之性質為觀念通知", "甲提起之訴願已逾訴願期間，訴願管轄機關應以無理由駁回甲之訴願", "甲不服該補件通知單，應向內政部提起訴願", "該補件通知單具有強制效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00104', 'colonel-7fec267e', 'colonel-7fec267e-moex-113-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '甲在河流旁搭建工寮並開闢菜園，經主管機關認定妨害水土保持屬於違 法，命甲限期回復原狀。甲不服，除循序提起訴願救濟外，得以下列何種 程序在救濟進行期間實現暫時權利保護？', '["應向行政法院聲請定暫時狀態假處分，由法院裁定該工寮及菜園暫時為 合法", "應向行政法院聲請保全處分，保全工寮及菜園之事實狀態", "應依據行政執行法向主管機關聲明異議", "應依行政訴訟法或訴願法聲請暫時停止執行該命回復原狀之處分 30830"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00105', 'colonel-7fec267e', 'colonel-7fec267e-moex-113-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '下列何者非屬確認行政處分無效之訴的實體判決要件？', '["確認對象須為行政處分之無效", "須已向原處分機關請求確認其無效未被允許或不為確答", "須經訴願程序而遭駁回", "須有即受確認判決之法律上利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00106', 'colonel-7fec267e', 'colonel-7fec267e-moex-113-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '關於行政訴訟制度之敘述，下列何者正確？', '["收容聲請事件適用以原就被之原則", "對於已執行而無回復原狀可能之行政處分，得提起確認該行政處分無效 之訴訟", "確認行政處分無效之訴訟，須已向原處分機關請求確認其無效未被允 許，或經請求後於30日內不為確答者，始得提起之", "受交通違規裁罰處分，應先經訴願程序，始得提起行政訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00107', 'colonel-7fec267e', 'colonel-7fec267e-moex-113-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '關於國家賠償法所規定之公共設施國家賠償責任，下列何者正確？', '["當公共設施已委託民間團體或個人管理時，國家即免除損害賠償責任", "於開放之山域、水域等自然公物，經管理機關、受委託管理之民間團體 或個人已就使用該公物為適當之警告或標示，而人民仍從事冒險或具危 險性活動，國家不負損害賠償責任", "於開放之山域、水域等自然公物內之設施，經管理機關、受委託管理之 民間團體或個人已就使用該公物為適當之警告或標示，而人民仍從事冒 險或具危險性活動，國家不負損害賠償責任", "就公共設施設置或管理之瑕疵應負責之第三人，賠償機關對之並無求 償權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00108', 'colonel-7fec267e', 'colonel-7fec267e-moex-113-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '關於行政損失補償之敘述，下列何者錯誤？', '["錯誤施打疫苗造成人民身體健康受損，基於準徵收法理應予補償", "對於犯罪被害人所為之補償，非基於特別犧牲", "土地徵收為合法、有目的性對人民財產權之侵害，故須給予補償", "為防止公益重大危害而廢止授益處分時，受益人得請求信賴利益損失 補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00109', 'colonel-7fec267e', 'colonel-7fec267e-moex-112-3a7b2121', 'sub-colonel-7fec267e-01', NULL, 'essay', '聯合國於2015年宣布了「2030永續發展目標」（SustainableDevelopment
Goals,SDGs），SDGs包含 17 項核心目標，其中又涵蓋了 169項細項目
標、230 項指標，指引全球共同努力、邁向永續。我國政府積極響應SDGs，
於民國 86 年 8 月 23 日行政院核定將原「行政院全球變遷政策指導小
組」提升擴大為「行政院國家永續發展委員會」，現由行政院院長親自
兼任主任委員，以示政府對永續發展的重視。請闡述推動實踐 SDGs 對
我國國家發展的影響與意義；（10 分）其次，請舉出我國中央或地方政
府所推動與施行之能夠契合 SDGs核心目標「終結貧窮」（SDG1）、「性
別平權」（SDG5）、「減少不平等」（SDG10）各一項政策法令且說明
